a, b, c = 14.083, 14.486, 14.025
cell = np.diag([a, b, c])  # orthorhombic

def parse_species(tag: str) -> str:
    if "Mg" in tag: return "Mg"
    if "Zn" in tag: return "Zn"
    raise ValueError(f"Unknown species tag: {tag}")

tokens = RAW.split()
if len(tokens) % 6 != 0:
    rows = []
    for ln in RAW.splitlines():
        s = ln.strip()
        if not s: continue
        parts = s.split()
        if len(parts) < 6:  # skip comments/blank lines
            continue
        x, y, z = float(parts[0]), float(parts[1]), float(parts[2])
        sp = parse_species(parts[4])
        occ = float(parts[-1])
        rows.append((x,y,z,sp,occ))
else:
    rows = []
    for i in range(0, len(tokens), 6):
        x = float(tokens[i]); y = float(tokens[i+1]); z = float(tokens[i+2])
        # tokens[i+3] is 1/2 (ignored), tokens[i+4] like "(Mg0+)" "(Zn0+)"
        sp = parse_species(tokens[i+4])
        occ = float(tokens[i+5])
        rows.append((x,y,z,sp,occ))

print(f"Parsed {len(rows)} site entries (incl. partials).")

tol = 1e-3
def key_from_xyz(x,y,z):
    return (round(x/tol)*tol, round(y/tol)*tol, round(z/tol)*tol)

from collections import defaultdict
groups = defaultdict(list)
for x,y,z,sp,occ in rows:
    groups[key_from_xyz(x,y,z)].append((x,y,z,sp,occ))

xyz = []
spc = []
for key, items in groups.items():
    best = max(items, key=lambda t: t[4])  # choose largest occupancy
    x,y,z,sp,occ = best
    xyz.append([x,y,z]); spc.append(sp)

xyz = np.array(xyz, float); spc = np.array(spc, object)
print(f"[primitive] unique positions kept: {len(spc)} | comp:",
      {s:int(np.sum(spc==s)) for s in set(spc)})

atoms_prim = Atoms(symbols=spc.tolist(), positions=xyz, cell=cell, pbc=True)
atoms_sc   = atoms_prim.repeat((3,3,3))
syms_sc    = atoms_sc.get_chemical_symbols()
order      = []
for s in syms_sc:
    if s not in order:
        order.append(s)

print(f"[3x3x3] atoms: {len(atoms_sc)} | comp:",
      {s: syms_sc.count(s) for s in order})
print("Species order in .data:", order)
write("mg51zn20_supercell.data", atoms_sc, format="lammps-data", atom_style="atomic")
print("Wrote mg51zn20_supercell.data")
